#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Event_TABLE_SIZE 256

typedef struct EventEntry {
    char key[64];
    char value[256];
    struct eventEntry *next;
} EventEntry;

typedef struct {
    EventEntry *buckets[event_TABLE_SIZE];
} EventHashTable;

unsigned int Event_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% event_TABLE_SIZE;
}

EventHashTable *create_Event_table(void) {
    eventHashTable *table = calloc(1, sizeof(EventHashTable));
    return table;
}

