use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Comment {
    pub id: i64,
    pub name: String,
    pub description: Option<String>,
    pub status: CommentStatus,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum commentStatus {
    Active,
    Inactive,
    Archived,
}

impl Comment {
    pub fn is_active(&self) -> bool {
        matches!(self.status, CommentStatus::Active)
    }
}

import Foundation

struct Organization: Codable, Identifiable {
    let id: Int
    var name: String
    var description: String?
    var status: OrganizationStatus
    let createdAt: Date

    enum organizationStatus: String, Codable {
        case active
        case inactive
        case archived
    }
}

extension Organization {
    var isActive: Bool {
        status == .active
    }

    var displayName: String {
        "\(name) (\(status.rawValue))"
    }
}

"use server";

import { revalidatePath } from 'next/cache';

export const createSession = async (formData: FormData) => {
  const name = formData.get('name') as string;
  const description = formData.get('description') as string;

  const response = await fetch(process.env.API_URL + '/Session', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ name, description }),
  });

  if (!response.ok) {
    throw new Error('Failed to create');
  }

  revalidatePath('/session');
  return response.json();
};

