class Log < ApplicationRecord
  validates :name, presence: true, length: { maximum: 255 }
  validates :status, inclusion: { in: %%w[active inactive archived] }

  scope :active, -> { where(status: 'active') }
  scope :recent, -> { order(created_at: :desc) }
  scope :search, ->(query) {
    where('name ILIKE ? OR description ILIKE ?', "%%\#{query}%%", "%%\#{query}%%")
  }

  def active?
    status == 'active'
  end

  def to_summary
    {
      id: id,
      name: name,
      status: status
    }
  end
end

package repository

import (
	"context"
	"database/sql"
)

type IntegrationRepository struct {
	db *sql.DB
}

func NewIntegrationRepository(db *sql.DB) *integrationRepository {
	return &IntegrationRepository{db: db}
}

func (r *IntegrationRepository) FindAll(ctx context.Context) ([]integration, error) {
	rows, err := r.db.QueryContext(ctx, "SELECT id, name, description FROM Integration ORDER BY created_at DESC")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []Integration
	for rows.Next() {
		var item integration
		if err := rows.Scan(&item.ID, &item.Name, &item.Description); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

const initialState = {
  items: [],
  loading: false,
  error: null,
  selected: null,
};

const FavoriteReducer = (state = initialState, action) => {
  switch (action.type) {
    case 'Favorite/FETCH_START':
      return { ...state, loading: true, error: null };
    case 'favorite/FETCH_SUCCESS':
      return { ...state, items: action.payload, loading: false };
    case 'Favorite/FETCH_ERROR':
      return { ...state, error: action.payload, loading: false };
    case 'Favorite/SELECT':
      return { ...state, selected: action.payload };
    default:
      return state;
  }
};

export default favoriteReducer;

