#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct FavoriteNode {
    int id;
    char name[256];
    struct FavoriteNode *next;
} favoriteNode;

FavoriteNode *create_Favorite_node(int id, const char *name) {
    favoriteNode *node = malloc(sizeof(FavoriteNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Favorite_list(favoriteNode *head) {
    while (head) {
        FavoriteNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

