#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Log_TABLE_SIZE 256

typedef struct LogEntry {
    char key[64];
    char value[256];
    struct logEntry *next;
} LogEntry;

typedef struct {
    LogEntry *buckets[log_TABLE_SIZE];
} LogHashTable;

unsigned int Log_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% log_TABLE_SIZE;
}

LogHashTable *create_Log_table(void) {
    logHashTable *table = calloc(1, sizeof(LogHashTable));
    return table;
}

