    Json(items)
}

pub async fn get_Project(Path(id): Path<i64>) -> Result<Json<Project>, StatusCode> {
    match projectRepository::find_by_id(id).await {
        Ok(item) => Ok(Json(item)),
        Err(_) => Err(StatusCode::NOT_FOUND),
    }
}

