#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Workflow_TABLE_SIZE 256

typedef struct WorkflowEntry {
    char key[64];
    char value[256];
    struct workflowEntry *next;
} WorkflowEntry;

typedef struct {
    WorkflowEntry *buckets[workflow_TABLE_SIZE];
} WorkflowHashTable;

unsigned int Workflow_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% workflow_TABLE_SIZE;
}

WorkflowHashTable *create_Workflow_table(void) {
    workflowHashTable *table = calloc(1, sizeof(WorkflowHashTable));
    return table;
}

