#include <stdlib.h>
#include <string.h>

typedef struct OrderNode {
    int id;
    char name[256];
    struct OrderNode *next;
} orderNode;

OrderNode *create_Order_node(int id, const char *name) {
    orderNode *node = malloc(sizeof(OrderNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Order_list(orderNode *head) {
    while (head) {
        OrderNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

