#define Chart_TABLE_SIZE 256

typedef struct ChartEntry {
    char key[64];
    char value[256];
    struct chartEntry *next;
} ChartEntry;

typedef struct {
    ChartEntry *buckets[chart_TABLE_SIZE];
} ChartHashTable;

unsigned int Chart_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% chart_TABLE_SIZE;
}

ChartHashTable *create_Chart_table(void) {
    chartHashTable *table = calloc(1, sizeof(ChartHashTable));
    return table;
}

