class AlertEmitter {
  constructor() {
    this.listeners = new Map();
  }

  on(event, callback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event).push(callback);
    return () => this.off(event, callback);
  }

  off(event, callback) {
    const callbacks = this.listeners.get(event) || [];
    this.listeners.set(event, callbacks.filter(cb => cb !== callback));
  }

  emit(event, data) {
    const callbacks = this.listeners.get(event) || [];
    callbacks.forEach(cb => cb(data));
  }
}

export default AlertEmitter;

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct NotificationNode {
    int id;
    char name[256];
    struct NotificationNode *next;
} notificationNode;

NotificationNode *create_Notification_node(int id, const char *name) {
    notificationNode *node = malloc(sizeof(NotificationNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Notification_list(notificationNode *head) {
    while (head) {
        NotificationNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

