package repository

import (
	"context"
	"database/sql"
)

type AuditRepository struct {
	db *sql.DB
}

func NewAuditRepository(db *sql.DB) *auditRepository {
	return &AuditRepository{db: db}
}

func (r *AuditRepository) FindAll(ctx context.Context) ([]audit, error) {
	rows, err := r.db.QueryContext(ctx, "SELECT id, name, description FROM Audit ORDER BY created_at DESC")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []Audit
	for rows.Next() {
		var item audit
		if err := rows.Scan(&item.ID, &item.Name, &item.Description); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

import Foundation

struct Report: Codable, Identifiable {
    let id: Int
    var name: String
    var description: String?
    var status: ReportStatus
    let createdAt: Date

    enum reportStatus: String, Codable {
        case active
        case inactive
        case archived
    }
}

extension Report {
    var isActive: Bool {
        status == .active
    }

    var displayName: String {
        "\(name) (\(status.rawValue))"
    }
}

package handler

import (
	"encoding/json"
	"net/http"
	"strconv"
)

type UserHandler struct {
	service UserService
}

func NewuserHandler(s UserService) *UserHandler {
	return &userHandler{service: s}
}

func (h *UserHandler) List(w http.ResponseWriter, r *http.Request) {
	items, err := h.service.FindAll(r.Context())
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(items)
}

