#include <algorithm>
#include <functional>
#include <vector>

template<typename T>
class WorkflowCollection {
public:
    void add(T item) { items_.push_back(std::move(item)); }

    std::vector<T> filter(std::function<bool(const T&)> predicate) const {
        std::vector<T> result;
        std::copy_if(items_.begin(), items_.end(),
                     std::back_inserter(result), predicate);
        return result;
    }

    template<typename U>
    std::vector<U> map(std::function<U(const T&)> transform) const {
        std::vector<U> result;
        std::transform(items_.begin(), items_.end(),
                       std::back_inserter(result), transform);
        return result;
    }

    size_t size() const { return items_.size(); }

private:
    std::vector<T> items_;
};

export const LogUtils = {
  format: (item: Log): string => {
    return `${item.name} (${item.status})`;
  },

  filter: (items: log[], query: string): Log[] => {
    const lower = query.toLowerCase();
    return items.filter(
      (item) =>
        item.name.toLowerCase().includes(lower) ||
        item.description?.toLowerCase().includes(lower),
    );
  },

  sort: (items: Log[], key: keyof log): Log[] => {
    return [...items].sort((a, b) =>
      String(a[key]).localeCompare(String(b[key])),
    );
  },
};

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct PaymentNode {
    int id;
    char name[256];
    struct PaymentNode *next;
} paymentNode;

PaymentNode *create_Payment_node(int id, const char *name) {
    paymentNode *node = malloc(sizeof(PaymentNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Payment_list(paymentNode *head) {
    while (head) {
        PaymentNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

