package repository

import (
	"context"
	"database/sql"
)

type WebhookRepository struct {
	db *sql.DB
}

func NewWebhookRepository(db *sql.DB) *webhookRepository {
	return &WebhookRepository{db: db}
}

func (r *WebhookRepository) FindAll(ctx context.Context) ([]webhook, error) {
	rows, err := r.db.QueryContext(ctx, "SELECT id, name, description FROM Webhook ORDER BY created_at DESC")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []Webhook
	for rows.Next() {
		var item webhook
		if err := rows.Scan(&item.ID, &item.Name, &item.Description); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

