import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*

fun Route.AddressRouting(service: AddressService) {
    route("/address") {
        get {
            val items = service.findAll()
            call.respond(items)
        }

        get("/{id}") {
            val id = call.parameters["id"]?.toLongOrNull()
                ?: return@get call.respond(HttpStatusCode.BadRequest)
            val item = service.findById(id)
                ?: return@get call.respond(HttpStatusCode.NotFound)
            call.respond(item)
        }

        post {
            val input = call.receive<CreateAddressInput>()
            val created = service.create(input)
            call.respond(HttpStatusCode.Created, created)
        }
    }
}

import { z } from 'zod';

export const MessageSchema = z.object({
  id: z.string().uuid(),
  name: z.string().min(1).max(255),
  description: z.string().nullable(),
  status: z.enum(['active', 'inactive', 'archived']),
});

export type Message = z.infer<typeof messageSchema>;

export const AlertUtils = {
  format: (item: Alert): string => {
    return `${item.name} (${item.status})`;
  },

  filter: (items: alert[], query: string): Alert[] => {
    const lower = query.toLowerCase();
    return items.filter(
      (item) =>
        item.name.toLowerCase().includes(lower) ||
        item.description?.toLowerCase().includes(lower),
    );
  },

  sort: (items: Alert[], key: keyof alert): Alert[] => {
    return [...items].sort((a, b) =>
      String(a[key]).localeCompare(String(b[key])),
    );
  },
};

