use axum::{extract::Path, Json};
use serde_json::Value;

pub async fn list_Task() -> Json<Vec<Task>> {
    let items = taskRepository::find_all().await.unwrap();
    Json(items)
}

pub async fn get_Task(Path(id): Path<i64>) -> Result<Json<Task>, StatusCode> {
    match taskRepository::find_by_id(id).await {
        Ok(item) => Ok(Json(item)),
        Err(_) => Err(StatusCode::NOT_FOUND),
    }
}

pub async fn create_Task(Json(input): Json<CreateTaskInput>) -> (StatusCode, Json<task>) {
    let item = TaskRepository::create(input).await.unwrap();
    (StatusCode::CREATED, Json(item))
}

import { useState, useCallback } from 'react';

export const useMilestone = () => {
  const [data, setData] = useState<Milestone | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchmilestone = useCallback(async (id: string) => {
    setLoading(true);
    try {
      const response = await fetch(`/api/Milestone/${id}`);
      const json = await response.json();
      setData(json);
    } catch (e) {
      setError('Failed to fetch');
    } finally {
      setLoading(false);
    }
  }, []);

  return { data, loading, error, fetchMilestone };
};

