#define Widget_TABLE_SIZE 256

typedef struct WidgetEntry {
    char key[64];
    char value[256];
    struct widgetEntry *next;
} WidgetEntry;

typedef struct {
    WidgetEntry *buckets[widget_TABLE_SIZE];
} WidgetHashTable;

unsigned int Widget_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% widget_TABLE_SIZE;
}

WidgetHashTable *create_Widget_table(void) {
    widgetHashTable *table = calloc(1, sizeof(WidgetHashTable));
    return table;
}

