fun Route.CommentRouting(service: CommentService) {
    route("/comment") {
        get {
            val items = service.findAll()
            call.respond(items)
        }

        get("/{id}") {
            val id = call.parameters["id"]?.toLongOrNull()
                ?: return@get call.respond(HttpStatusCode.BadRequest)
            val item = service.findById(id)
                ?: return@get call.respond(HttpStatusCode.NotFound)
            call.respond(item)
        }

        post {
            val input = call.receive<CreateCommentInput>()
            val created = service.create(input)
            call.respond(HttpStatusCode.Created, created)
        }
    }
}

package repository

import (
	"context"
	"database/sql"
)

type TokenRepository struct {
	db *sql.DB
}

func NewTokenRepository(db *sql.DB) *tokenRepository {
	return &TokenRepository{db: db}
}

func (r *TokenRepository) FindAll(ctx context.Context) ([]token, error) {
	rows, err := r.db.QueryContext(ctx, "SELECT id, name, description FROM Token ORDER BY created_at DESC")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []Token
	for rows.Next() {
		var item token
		if err := rows.Scan(&item.ID, &item.Name, &item.Description); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

import SwiftUI

struct ReviewListView: View {
    @StateObject private var viewModel = ReviewViewModel()

    var body: some View {
        NavigationStack {
            List(viewModel.items) { item in
                NavigationLink(destination: reviewDetailView(item: item)) {
                    VStack(alignment: .leading) {
                        Text(item.name)
                            .font(.headline)
                        Text(item.description ?? "")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle("Review")
            .task { await viewModel.fetchAll() }
        }
    }
}

