#define Session_TABLE_SIZE 256

typedef struct SessionEntry {
    char key[64];
    char value[256];
    struct sessionEntry *next;
} SessionEntry;

typedef struct {
    SessionEntry *buckets[session_TABLE_SIZE];
} SessionHashTable;

unsigned int Session_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% session_TABLE_SIZE;
}

SessionHashTable *create_Session_table(void) {
    sessionHashTable *table = calloc(1, sizeof(SessionHashTable));
    return table;
}

class AuditEmitter {
  constructor() {
    this.listeners = new Map();
  }

  on(event, callback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event).push(callback);
    return () => this.off(event, callback);
  }

  off(event, callback) {
    const callbacks = this.listeners.get(event) || [];
    this.listeners.set(event, callbacks.filter(cb => cb !== callback));
  }

  emit(event, data) {
    const callbacks = this.listeners.get(event) || [];
    callbacks.forEach(cb => cb(data));
  }
}

export default AuditEmitter;

