class Project < ApplicationRecord
  validates :name, presence: true, length: { maximum: 255 }
  validates :status, inclusion: { in: %%w[active inactive archived] }

  scope :active, -> { where(status: 'active') }
  scope :recent, -> { order(created_at: :desc) }
  scope :search, ->(query) {
    where('name ILIKE ? OR description ILIKE ?', "%%\#{query}%%", "%%\#{query}%%")
  }

  def active?
    status == 'active'
  end

  def to_summary
    {
      id: id,
      name: name,
      status: status
    }
  end
end

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Report_TABLE_SIZE 256

typedef struct ReportEntry {
    char key[64];
    char value[256];
    struct reportEntry *next;
} ReportEntry;

typedef struct {
    ReportEntry *buckets[report_TABLE_SIZE];
} ReportHashTable;

unsigned int Report_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% report_TABLE_SIZE;
}

ReportHashTable *create_Report_table(void) {
    reportHashTable *table = calloc(1, sizeof(ReportHashTable));
    return table;
}

