import (
	"context"
	"database/sql"
)

type MetricRepository struct {
	db *sql.DB
}

func NewMetricRepository(db *sql.DB) *metricRepository {
	return &MetricRepository{db: db}
}

func (r *MetricRepository) FindAll(ctx context.Context) ([]metric, error) {
	rows, err := r.db.QueryContext(ctx, "SELECT id, name, description FROM Metric ORDER BY created_at DESC")
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []Metric
	for rows.Next() {
		var item metric
		if err := rows.Scan(&item.ID, &item.Name, &item.Description); err != nil {
			return nil, err
		}
		items = append(items, item)
	}
	return items, nil
}

import { useState, useCallback } from 'react';

export const useOrganization = () => {
  const [data, setData] = useState<Organization | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchorganization = useCallback(async (id: string) => {
    setLoading(true);
    try {
      const response = await fetch(`/api/Organization/${id}`);
      const json = await response.json();
      setData(json);
    } catch (e) {
      setError('Failed to fetch');
    } finally {
      setLoading(false);
    }
  }, []);

  return { data, loading, error, fetchOrganization };
};

