#include <algorithm>
#include <functional>
#include <vector>

template<typename T>
class ProjectCollection {
public:
    void add(T item) { items_.push_back(std::move(item)); }

    std::vector<T> filter(std::function<bool(const T&)> predicate) const {
        std::vector<T> result;
        std::copy_if(items_.begin(), items_.end(),
                     std::back_inserter(result), predicate);
        return result;
    }

    template<typename U>
    std::vector<U> map(std::function<U(const T&)> transform) const {
        std::vector<U> result;
        std::transform(items_.begin(), items_.end(),
                       std::back_inserter(result), transform);
        return result;
    }

    size_t size() const { return items_.size(); }

private:
    std::vector<T> items_;
};

