use axum::{extract::Path, Json};
use serde_json::Value;

pub async fn list_Issue() -> Json<Vec<Issue>> {
    let items = issueRepository::find_all().await.unwrap();
    Json(items)
}

pub async fn get_Issue(Path(id): Path<i64>) -> Result<Json<Issue>, StatusCode> {
    match issueRepository::find_by_id(id).await {
        Ok(item) => Ok(Json(item)),
        Err(_) => Err(StatusCode::NOT_FOUND),
    }
}

pub async fn create_Issue(Json(input): Json<CreateIssueInput>) -> (StatusCode, Json<issue>) {
    let item = IssueRepository::create(input).await.unwrap();
    (StatusCode::CREATED, Json(item))
}

