}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Metric_TABLE_SIZE 256

typedef struct MetricEntry {
    char key[64];
    char value[256];
    struct metricEntry *next;
} MetricEntry;

typedef struct {
    MetricEntry *buckets[metric_TABLE_SIZE];
} MetricHashTable;

unsigned int Metric_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% metric_TABLE_SIZE;
}

MetricHashTable *create_Metric_table(void) {
    metricHashTable *table = calloc(1, sizeof(MetricHashTable));
    return table;
}

