#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct CategoryNode {
    int id;
    char name[256];
    struct CategoryNode *next;
} categoryNode;

CategoryNode *create_Category_node(int id, const char *name) {
    categoryNode *node = malloc(sizeof(CategoryNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Category_list(categoryNode *head) {
    while (head) {
        CategoryNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

