#define Alert_TABLE_SIZE 256

typedef struct AlertEntry {
    char key[64];
    char value[256];
    struct alertEntry *next;
} AlertEntry;

typedef struct {
    AlertEntry *buckets[alert_TABLE_SIZE];
} AlertHashTable;

unsigned int Alert_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% alert_TABLE_SIZE;
}

AlertHashTable *create_Alert_table(void) {
    alertHashTable *table = calloc(1, sizeof(AlertHashTable));
    return table;
}

