typedef struct ReviewNode {
    int id;
    char name[256];
    struct ReviewNode *next;
} reviewNode;

ReviewNode *create_Review_node(int id, const char *name) {
    reviewNode *node = malloc(sizeof(ReviewNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Review_list(reviewNode *head) {
    while (head) {
        ReviewNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

