typedef struct TeamNode {
    int id;
    char name[256];
    struct TeamNode *next;
} teamNode;

TeamNode *create_Team_node(int id, const char *name) {
    teamNode *node = malloc(sizeof(TeamNode));
    if (!node) return NULL;
    node->id = id;
    strncpy(node->name, name, 255);
    node->name[255] = '\0';
    node->next = NULL;
    return node;
}

void free_Team_list(teamNode *head) {
    while (head) {
        TeamNode *tmp = head;
        head = head->next;
        free(tmp);
    }
}

