import { useState, useCallback } from 'react';

export const useLabel = () => {
  const [data, setData] = useState<Label | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchlabel = useCallback(async (id: string) => {
    setLoading(true);
    try {
      const response = await fetch(`/api/Label/${id}`);
      const json = await response.json();
      setData(json);
    } catch (e) {
      setError('Failed to fetch');
    } finally {
      setLoading(false);
    }
  }, []);

  return { data, loading, error, fetchLabel };
};

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define Project_TABLE_SIZE 256

typedef struct ProjectEntry {
    char key[64];
    char value[256];
    struct projectEntry *next;
} ProjectEntry;

typedef struct {
    ProjectEntry *buckets[project_TABLE_SIZE];
} ProjectHashTable;

unsigned int Project_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% project_TABLE_SIZE;
}

ProjectHashTable *create_Project_table(void) {
    projectHashTable *table = calloc(1, sizeof(ProjectHashTable));
    return table;
}

