#define Dashboard_TABLE_SIZE 256

typedef struct DashboardEntry {
    char key[64];
    char value[256];
    struct dashboardEntry *next;
} DashboardEntry;

typedef struct {
    DashboardEntry *buckets[dashboard_TABLE_SIZE];
} DashboardHashTable;

unsigned int Dashboard_hash(const char *key) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash %% dashboard_TABLE_SIZE;
}

DashboardHashTable *create_Dashboard_table(void) {
    dashboardHashTable *table = calloc(1, sizeof(DashboardHashTable));
    return table;
}

