use axum::{extract::Path, Json};
use serde_json::Value;

pub async fn list_Message() -> Json<Vec<Message>> {
    let items = messageRepository::find_all().await.unwrap();
    Json(items)
}

pub async fn get_Message(Path(id): Path<i64>) -> Result<Json<Message>, StatusCode> {
    match messageRepository::find_by_id(id).await {
        Ok(item) => Ok(Json(item)),
        Err(_) => Err(StatusCode::NOT_FOUND),
    }
}

pub async fn create_Message(Json(input): Json<CreateMessageInput>) -> (StatusCode, Json<message>) {
    let item = MessageRepository::create(input).await.unwrap();
    (StatusCode::CREATED, Json(item))
}

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct User {
    pub id: i64,
    pub name: String,
    pub description: Option<String>,
    pub status: UserStatus,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum userStatus {
    Active,
    Inactive,
    Archived,
}

impl User {
    pub fn is_active(&self) -> bool {
        matches!(self.status, UserStatus::Active)
    }
}

import { useState, useCallback } from 'react';

export const useTask = () => {
  const [data, setData] = useState<Task | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchtask = useCallback(async (id: string) => {
    setLoading(true);
    try {
      const response = await fetch(`/api/Task/${id}`);
      const json = await response.json();
      setData(json);
    } catch (e) {
      setError('Failed to fetch');
    } finally {
      setLoading(false);
    }
  }, []);

  return { data, loading, error, fetchTask };
};

import SwiftUI

struct ContactListView: View {
    @StateObject private var viewModel = ContactViewModel()

    var body: some View {
        NavigationStack {
            List(viewModel.items) { item in
                NavigationLink(destination: contactDetailView(item: item)) {
                    VStack(alignment: .leading) {
                        Text(item.name)
                            .font(.headline)
                        Text(item.description ?? "")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle("Contact")
            .task { await viewModel.fetchAll() }
        }
    }
}

class Token < ApplicationRecord
  validates :name, presence: true, length: { maximum: 255 }
  validates :status, inclusion: { in: %%w[active inactive archived] }

  scope :active, -> { where(status: 'active') }
  scope :recent, -> { order(created_at: :desc) }
  scope :search, ->(query) {
    where('name ILIKE ? OR description ILIKE ?', "%%\#{query}%%", "%%\#{query}%%")
  }

  def active?
    status == 'active'
  end

  def to_summary
    {
      id: id,
      name: name,
      status: status
    }
  end
end

